// FreeLang v1 - Example 1: Basic Syntax
// Features: Functions, variables, control flow, basic types

// 함수 정의
fn greet(name: string) -> string {
    return "Hello, " + name + "!"
}

// 변수와 기본 타입
fn calculate_sum() -> int {
    let x: int = 10
    let y: int = 20
    let result: int = x + y
    return result
}

// 제어문 (if/else)
fn check_number(n: int) -> string {
    if n > 0 {
        return "Positive"
    } else if n < 0 {
        return "Negative"
    } else {
        return "Zero"
    }
}

// 루프 (for, while)
fn print_numbers(count: int) -> void {
    let i: int = 0
    while i < count {
        print(i)
        i = i + 1
    }
}

// 메인 함수 진입점
fn main() -> void {
    let greeting: string = greet("World")
    print(greeting)

    let sum: int = calculate_sum()
    print("Sum: " + sum)

    let status: string = check_number(5)
    print("Status: " + status)

    print_numbers(5)
}

// FreeLang v1 - Example 2: Array Processing
// Features: Arrays, simple iteration, basic operations

// 배열 선언 및 초기화
fn create_array() -> array<int> {
    let arr: array<int> = [1, 2, 3, 4, 5]
    return arr
}

// 배열의 합 계산
fn sum_array(arr: array<int>) -> int {
    let sum: int = 0
    let i: int = 0

    while i < len(arr) {
        sum = sum + arr[i]
        i = i + 1
    }

    return sum
}

// 배열의 최대값 찾기
fn find_max(arr: array<int>) -> int {
    let max: int = arr[0]
    let i: int = 1

    while i < len(arr) {
        if arr[i] > max {
            max = arr[i]
        }
        i = i + 1
    }

    return max
}

// 배열에서 짝수만 필터링
fn filter_even(arr: array<int>) -> array<int> {
    let result: array<int> = []
    let i: int = 0

    while i < len(arr) {
        if arr[i] % 2 == 0 {
            result = push(result, arr[i])
        }
        i = i + 1
    }

    return result
}

// 배열의 모든 요소에 2를 곱함
fn multiply_by_two(arr: array<int>) -> array<int> {
    let result: array<int> = []
    let i: int = 0

    while i < len(arr) {
        result = push(result, arr[i] * 2)
        i = i + 1
    }

    return result
}

// 메인 함수
fn main() -> void {
    let numbers: array<int> = create_array()
    print("Original array: [1, 2, 3, 4, 5]")

    let total: int = sum_array(numbers)
    print("Sum: " + total)

    let max_val: int = find_max(numbers)
    print("Max: " + max_val)

    let evens: array<int> = filter_even(numbers)
    print("Even numbers found: " + len(evens))

    let doubled: array<int> = multiply_by_two(numbers)
    print("Doubled: [2, 4, 6, 8, 10]")
}

// FreeLang v2 - Example 1: Enhanced Type System
// Features: Union types, Option<T>, Result<T,E>, Pattern matching

// Option 타입 사용
fn find_in_array(arr: array<int>, target: int) -> Option<int> {
    let i: int = 0
    while i < len(arr) {
        if arr[i] == target {
            return Some(i)
        }
        i = i + 1
    }
    return None()
}

// Result 타입으로 에러 표현
fn divide(a: int, b: int) -> Result<int, string> {
    if b == 0 {
        return Err("Division by zero")
    }
    return Ok(a / b)
}

// Union 타입 (여러 타입 가능)
union Value {
    IntVal(int),
    StringVal(string),
    FloatVal(float)
}

// Union 타입 처리
fn process_value(val: Value) -> string {
    match val {
        IntVal(n) => {
            return "Integer: " + n
        }
        StringVal(s) => {
            return "String: " + s
        }
        FloatVal(f) => {
            return "Float: " + f
        }
    }
}

// 재귀 함수 (v2에서 지원)
fn factorial(n: int) -> Result<int, string> {
    if n < 0 {
        return Err("Cannot compute factorial of negative number")
    }
    if n == 0 {
        return Ok(1)
    }

    match factorial(n - 1) {
        Ok(prev_result) => {
            return Ok(n * prev_result)
        }
        Err(e) => {
            return Err(e)
        }
    }
}

// 제네릭 함수
fn swap<T>(a: T, b: T) -> (T, T) {
    return (b, a)
}

// 메인 함수
fn main() -> void {
    // Option 처리
    let arr: array<int> = [1, 2, 3, 4, 5]
    match find_in_array(arr, 3) {
        Some(idx) => {
            print("Found at index: " + idx)
        }
        None() => {
            print("Not found")
        }
    }

    // Result 처리
    match divide(10, 2) {
        Ok(result) => {
            print("Division result: " + result)
        }
        Err(e) => {
            print("Error: " + e)
        }
    }

    // Union 처리
    let val1: Value = IntVal(42)
    let val2: Value = StringVal("Hello")
    print(process_value(val1))
    print(process_value(val2))

    // 재귀 함수
    match factorial(5) {
        Ok(result) => {
            print("5! = " + result)
        }
        Err(e) => {
            print("Error: " + e)
        }
    }

    // 제네릭
    let (x, y) = swap(10, 20)
    print("Swapped: " + x + ", " + y)
}

// FreeLang v2 - Example 2: Error Handling
// Features: Result<T,E>, try-catch, custom error types, error propagation

// 커스텀 에러 타입
union ParseError {
    InvalidFormat,
    OutOfRange,
    NotFound
}

// 문자열을 정수로 변환 (Result 반환)
fn parse_int(s: string) -> Result<int, ParseError> {
    if len(s) == 0 {
        return Err(InvalidFormat)
    }

    // 매우 단순한 파싱 (v2 스타일)
    match s {
        "0" => { return Ok(0) }
        "1" => { return Ok(1) }
        "42" => { return Ok(42) }
        _ => { return Err(InvalidFormat) }
    }
}

// 범위 검증
fn validate_range(n: int) -> Result<int, ParseError> {
    if n < 0 {
        return Err(OutOfRange)
    }
    if n > 100 {
        return Err(OutOfRange)
    }
    return Ok(n)
}

// 에러 전파 - 연쇄 처리
fn process_input(s: string) -> Result<int, ParseError> {
    match parse_int(s) {
        Ok(n) => {
            match validate_range(n) {
                Ok(valid_n) => {
                    return Ok(valid_n)
                }
                Err(e) => {
                    return Err(e)
                }
            }
        }
        Err(e) => {
            return Err(e)
        }
    }
}

// 에러 메시지 생성
fn error_message(err: ParseError) -> string {
    match err {
        InvalidFormat => {
            return "Invalid format provided"
        }
        OutOfRange => {
            return "Value out of range (0-100)"
        }
        NotFound => {
            return "Value not found"
        }
    }
}

// Safe division with error handling
fn safe_divide(a: int, b: int) -> Result<int, string> {
    if b == 0 {
        return Err("Cannot divide by zero")
    }
    return Ok(a / b)
}

// 배열에서 요소 찾기 - Result 반환
fn find_element(arr: array<int>, target: int) -> Result<int, ParseError> {
    let i: int = 0
    while i < len(arr) {
        if arr[i] == target {
            return Ok(i)
        }
        i = i + 1
    }
    return Err(NotFound)
}

// 메인 함수 - 에러 처리 데모
fn main() -> void {
    print("=== Error Handling Demo ===")

    // 사례 1: 성공적인 파싱
    match process_input("42") {
        Ok(n) => {
            print("Parsed successfully: " + n)
        }
        Err(e) => {
            print("Error: " + error_message(e))
        }
    }

    // 사례 2: 범위 초과
    match process_input("150") {
        Ok(n) => {
            print("Parsed successfully: " + n)
        }
        Err(e) => {
            print("Error: " + error_message(e))
        }
    }

    // 사례 3: 잘못된 형식
    match process_input("abc") {
        Ok(n) => {
            print("Parsed successfully: " + n)
        }
        Err(e) => {
            print("Error: " + error_message(e))
        }
    }

    // 사례 4: 안전한 나눗셈
    match safe_divide(10, 2) {
        Ok(result) => {
            print("Division result: " + result)
        }
        Err(e) => {
            print("Error: " + e)
        }
    }

    match safe_divide(10, 0) {
        Ok(result) => {
            print("Division result: " + result)
        }
        Err(e) => {
            print("Error: " + e)
        }
    }

    // 사례 5: 배열 검색
    let numbers: array<int> = [10, 20, 30, 40, 50]
    match find_element(numbers, 30) {
        Ok(idx) => {
            print("Found at index: " + idx)
        }
        Err(e) => {
            print("Error: " + error_message(e))
        }
    }

    match find_element(numbers, 99) {
        Ok(idx) => {
            print("Found at index: " + idx)
        }
        Err(e) => {
            print("Error: " + error_message(e))
        }
    }
}

