// FreeLang v4 - Example 2: Concurrency & Actor Model
// Features: Actors, channels, async/await, concurrent operations, supervision

use concurrency::{Actor, Channel, spawn, await, select}
use errors::{Result, Error}

// Actor 메시지 타입 (디자인 패턴)
union WorkerMessage {
    Task(int),
    Cancel,
    Status
}

union WorkerResponse {
    Result(int),
    Cancelled,
    Busy
}

// Worker Actor - 작업 처리
actor Worker {
    id: int,
    busy: bool,
    tasks_completed: int,

    // 메시지 핸들러
    fn handle_message(msg: WorkerMessage) -> WorkerResponse {
        match msg {
            Task(work_id) => {
                self.busy = true
                self.tasks_completed = self.tasks_completed + 1
                // 작업 시뮬레이션
                let result: int = self.process_work(work_id)
                self.busy = false
                return Result(result)
            }
            Cancel => {
                self.busy = false
                return Cancelled
            }
            Status => {
                if self.busy {
                    return Busy
                } else {
                    return Result(self.tasks_completed)
                }
            }
        }
    }

    fn process_work(work_id: int) -> int {
        // 실제 작업
        let result: int = work_id * 2
        return result
    }
}

// 작업 큐 Actor - 작업 분배
actor WorkQueue {
    workers: array<Actor<WorkerMessage, WorkerResponse>>,
    queue: array<int>,
    next_worker: int,

    fn distribute_work() -> Result<void, Error> {
        // 대기 중인 작업을 워커에게 분배
        while len(self.queue) > 0 {
            let work_id: int = self.queue[0]
            self.queue = slice(self.queue, 1, len(self.queue))

            let worker: Actor<WorkerMessage, WorkerResponse> =
                self.workers[self.next_worker]

            let response: WorkerResponse = worker.send(Task(work_id)).await
            self.next_worker = (self.next_worker + 1) % len(self.workers)
        }
        return Ok()
    }

    fn add_work(work_id: int) -> void {
        self.queue = push(self.queue, work_id)
    }
}

// 채널을 이용한 통신
fn example_channels() -> Result<void, Error> {
    // 채널 생성 (발신자, 수신자 분리)
    let (sender, receiver) = channel<string>()

    // 발신 작업
    spawn(fn() -> void {
        sender.send("Hello from async task")
    })

    // 수신 작업
    spawn(fn() -> void {
        match receiver.recv().await {
            Some(msg) => {
