// 동시 작업 (fork-join)
async fn concurrent_tasks() -> Result<array<int>, Error> {
    let results: array<int> = []

    // 3개 비동기 작업 동시 실행
    let task1 = spawn(async fn() -> int { return 10 })
    let task2 = spawn(async fn() -> int { return 20 })
    let task3 = spawn(async fn() -> int { return 30 })

    // 모든 작업 완료 대기
    let r1: int = task1.await
    let r2: int = task2.await
    let r3: int = task3.await

    results = push(results, r1)
    results = push(results, r2)
    results = push(results, r3)

    return Ok(results)
}

// 배치 처리 (Batch Processing)
async fn batch_processing(items: array<int>, batch_size: int) -> Result<int, Error> {
    let total: int = 0
    let batch: array<int> = []

    let i: int = 0
    while i < len(items) {
        batch = push(batch, items[i])

        if len(batch) == batch_size {
            // 배치 처리
            let batch_result: int = process_batch(batch).await
            total = total + batch_result
            batch = []
        }

        i = i + 1
    }

    // 남은 항목 처리
    if len(batch) > 0 {
        let batch_result: int = process_batch(batch).await
        total = total + batch_result
    }

    return Ok(total)
}

async fn process_batch(batch: array<int>) -> int {
    let result: int = 0
    let i: int = 0

    while i < len(batch) {
        result = result + batch[i]
        i = i + 1
    }

    return result
}

// 뮤텍스를 이용한 공유 상태 보호
use concurrency::Mutex

fn shared_state_example() -> Result<void, Error> {
    let counter: Mutex<int> = Mutex::new(0)

    // 여러 태스크에서 안전하게 증가
    spawn(fn() -> void {
        let mut guard = counter.lock().unwrap()
        *guard = *guard + 1
    })

    spawn(fn() -> void {
        let mut guard = counter.lock().unwrap()
        *guard = *guard + 1
    })

    // 결과 읽기
    match counter.lock() {
        Ok(guard) => {
            print("Counter: " + *guard)
        }
        Err(e) => {
            return Err(Error::LockFailed)
        }
    }

    return Ok()
}

