// 트레이싱 대상: 데이터 처리 파이프라인
@trace("data.pipeline")
fn process_user_data(user_id: int, action: string) -> Result<map<string, any>, Error> {
    let trace_ctx: TraceContext = TraceContext::current()
    trace_ctx.span_start("load_user")

    // 데이터 로드
    let user: User = load_user(user_id).await
    trace_ctx.log("user.loaded", {
        "user_id": user_id,
        "user_name": user.name,
        "trace_depth": 1
    })

    trace_ctx.span_end("load_user")
    trace_ctx.span_start("validate_action")

    // 액션 검증
    match validate_action(user, action) {
        Ok() => {
            trace_ctx.log("action.validated", {
                "action": action,
                "status": "valid"
            })
        }
        Err(e) => {
            trace_ctx.error("action.validation_failed", {
                "error": e.message,
                "severity": "high"
            })
            return Err(e)
        }
    }

    trace_ctx.span_end("validate_action")
    trace_ctx.span_start("execute_action")

    // 액션 실행
    let result: map<string, any> = execute_action(user, action).await
    trace_ctx.log("action.executed", {
        "action": action,
        "result_keys": result.keys()
    })

    trace_ctx.span_end("execute_action")

    return Ok(result)
}

// 2차원 관찰성: 수평 (같은 레벨 호출) + 수직 (계층 구조)
