// 데이터 흐름 추적 (Data Flow Graph)
@trace_dataflow
fn data_flow_example(input: array<int>) -> int {
    // 입력: input=[1,2,3,4,5]
    // 흐름:
    //   input -[filter_even]-> [2,4]
    //   [2,4] -[multiply_by_3]-> [6,12]
