    let multiplied: array<int> = multiply_by_three(filtered)
    trace_dataflow.log({
        "stage": "multiply",
        "input_size": len(filtered),
        "output_size": len(multiplied)
    })

    let result: int = sum_array(multiplied)
    trace_dataflow.log({
        "stage": "sum",
        "input_size": len(multiplied),
        "result": result
    })

    return result
}

// 경로 분석 (Path Analysis) - 어느 경로가 호출되었나?
@analyze_paths
fn conditional_logic(value: int) -> string {
    // 경로 1: value < 0
    // 경로 2: value >= 0 && value < 10
    // 경로 3: value >= 10

    let path_tracer: PathAnalysis = PathAnalysis::new()

    if value < 0 {
        path_tracer.record_path("negative_path")
        return "negative"
    } else if value < 10 {
        path_tracer.record_path("small_positive_path")
        return "small"
    } else {
        path_tracer.record_path("large_positive_path")
        return "large"
    }
}

// 메트릭 수집 (v5의 자동화)
@auto_metrics
fn expensive_operation(items: array<int>) -> int {
    // v5: 자동으로 메트릭 수집
    let counter: Counter = Counter::new("expensive_ops_total")
    let histogram: Histogram = Histogram::new("operation_duration_ms")

    counter.inc()

    let start_time: int = timestamp()
    let result: int = 0
    let i: int = 0

    while i < len(items) {
        result = result + items[i]
        i = i + 1
    }

    let duration: int = timestamp() - start_time
    histogram.observe(duration)

    return result
}

