fn filter_even(arr: array<int>) -> array<int> {
    let result: array<int> = []
    let i: int = 0
    while i < len(arr) {
        if arr[i] % 2 == 0 {
            result = push(result, arr[i])
        }
        i = i + 1
    }
    return result
}

fn multiply_by_three(arr: array<int>) -> array<int> {
    let result: array<int> = []
    let i: int = 0
    while i < len(arr) {
        result = push(result, arr[i] * 3)
        i = i + 1
    }
    return result
}

fn sum_array(arr: array<int>) -> int {
    let sum: int = 0
    let i: int = 0
    while i < len(arr) {
        sum = sum + arr[i]
        i = i + 1
    }
    return sum
}

