// AI 기반 성능 분석 (실시간)
@ai_profile
fn slow_algorithm(n: int) -> int {
    // v5: AI가 실시간으로 성능 분석
    // AI 감지: "이 함수는 O(n^2), 최적화 가능"
    let result: int = 0
    let i: int = 0

    while i < n {
        let j: int = 0
        while j < n {
            result = result + 1
            j = j + 1
        }
        i = i + 1
    }

    return result
}

