// 의존 타입 (Dependent Types)
// 특정 조건을 만족하는 값만 허용
type PositiveInt = int where self > 0
type ZeroToHundred = int where self >= 0 && self <= 100
type NonEmptyArray<T> = array<T> where len(self) > 0

// Phantom Type - 실행 시간에 추적
type Celsius = float @phantom
type Fahrenheit = float @phantom

// 선형 타입 (Linear Type) - 정확히 한 번만 사용
type LinearResource = resource

// 함수 서명에서 타입 안전성 보장
fn divide(a: int, b: PositiveInt) -> int {
    // b > 0이 보장되므로 안전
    return a / b.value
}

fn celsius_to_fahrenheit(c: Celsius) -> Fahrenheit {
    // 타입 변환도 명시적
    return Fahrenheit((c.value * 9.0 / 5.0) + 32.0)
}

// Refinement Type를 사용한 더 정밀한 검사
fn validate_email(email: string) -> Result<ValidEmail, ValidationError> {
    // ValidEmail은 "@"를 포함하고 길이가 5-254인 문자열
    if !contains(email, "@") {
        return Err(ValidationError::NoAtSign)
    }
    if len(email) < 5 || len(email) > 254 {
        return Err(ValidationError::InvalidLength)
    }

    return Ok(ValidEmail(email))
}

type ValidEmail = string where contains(self, "@") && len(self) >= 5 && len(self) <= 254

// Generic Constraint - 제네릭의 완벽한 타입 체크
fn find_max<T: Comparable>(arr: NonEmptyArray<T>) -> T {
    // arr이 비어있지 않음이 타입으로 보장됨
    let max: T = arr[0]
    let i: int = 1

    while i < len(arr) {
        if arr[i] > max {
            max = arr[i]
        }
        i = i + 1
    }

    return max
}

