// 캡슐화 강화 (Encapsulation)
@sealed
class Counter {
    private count: int

    fn new() -> Counter {
        return Counter { count: 0 }
    }

    fn increment() -> void {
        self.count = self.count + 1
    }

    fn get() -> int {
        return self.count
    }

    // count 필드는 외부에서 접근 불가능
}

// Existential Type - 인터페이스의 완벽한 구현
type Iterator<T> = exists I. {
    has_next: fn() -> bool,
    next: fn() -> T
}

fn consume_iterator<T>(iter: Iterator<T>) -> array<T> {
    let result: array<T> = []

    while iter.has_next() {
        result = push(result, iter.next())
    }

    return result
}

// Higher-Ranked Type - 함수형 프로그래밍 완벽 지원
fn apply_to_all<A, B>(f: forall T. (T) -> T, arr: array<A>) -> array<A> {
    // f는 모든 타입에 대해 작동
    let result: array<A> = []
    let i: int = 0

    while i < len(arr) {
        result = push(result, f(arr[i]))
        i = i + 1
    }

    return result
}

// Row Polymorphism - 유연한 구조체 타입
type RecordWithId = {
    id: int,
    ...rest: any  // 다른 필드 허용
}

fn get_id_safe(record: RecordWithId) -> int {
