fn extract_with_type_guard(dyn_val: dynamic, expected_type: type) -> Result<any, TypeError> {
    // 런타임 타입 검사
    if dyn_val.typeof() == expected_type {
        return Ok(dyn_val.value)
    } else {
        return Err(TypeError::Mismatch)
    }
}

