// FreeLang v6 - Example 2: Production-Grade Error Handling
// Features: Comprehensive error types, recovery strategies, observability, circuit breaker

use errors::{Result, Error, Recovery, CircuitBreaker}
use observability::{Logger, Metrics, Alert}
use retry::{RetryPolicy, Backoff}

// 상세한 에러 타입 정의
@exhaustive
union AppError {
    ValidationError {
        field: string,
        reason: string
    },
    NetworkError {
        code: int,
        message: string,
        retryable: bool
    },
    DatabaseError {
        operation: string,
        details: string,
        recoverable: bool
    },
    AuthenticationError {
        reason: string,
        attempts: int
    },
    InternalError {
        component: string,
        message: string,
        stack_trace: array<string>
    }
}

// 에러 원인 추적 (Error Chain)
type ErrorContext = {
    error: AppError,
    cause: Option<ErrorContext>,
    timestamp: int,
    component: string,
    request_id: string
}

// 복구 전략 (Recovery Strategy)
@trait
trait ErrorRecovery {
    fn can_recover(error: AppError) -> bool
    fn recover(error: AppError) -> Result<any, AppError>
}

// 네트워크 에러 복구
struct NetworkErrorRecovery {
    max_retries: int,
    backoff_strategy: Backoff
}

impl ErrorRecovery for NetworkErrorRecovery {
    fn can_recover(error: AppError) -> bool {
        match error {
            NetworkError { retryable, .. } => {
                return retryable
            }
            _ => {
                return false
            }
        }
    }

    fn recover(error: AppError) -> Result<any, AppError> {
        // 재시도 로직
        let attempt: int = 0
        while attempt < self.max_retries {
            // 지수 백오프로 대기
            let delay: int = self.backoff_strategy.calculate(attempt)
            sleep(delay)

            // 재시도
            match retry_network_operation() {
                Ok(result) => {
                    return Ok(result)
                }
                Err(e) => {
                    attempt = attempt + 1
                    // 계속 시도
                }
            }
        }

        return Err(error)
    }
}

// 데이터베이스 에러 복구
struct DatabaseErrorRecovery {
    connection_pool: ConnectionPool
}

impl ErrorRecovery for DatabaseErrorRecovery {
    fn can_recover(error: AppError) -> bool {
        match error {
            DatabaseError { recoverable, .. } => {
                return recoverable
            }
            _ => {
                return false
            }
        }
    }

    fn recover(error: AppError) -> Result<any, AppError> {
        // 연결 재설정
        match self.connection_pool.reset() {
            Ok() => {
                return Ok()
            }
            Err(e) => {
                return Err(error)
            }
        }
    }
}

// 서킷 브레이커 패턴
@circuit_breaker
struct ServiceCircuitBreaker {
    failure_threshold: int,
    success_threshold: int,
    timeout: int,
    state: string,  // "closed", "open", "half_open"
    failure_count: int,
    success_count: int,
    last_failure_time: int
}

impl ServiceCircuitBreaker {
    fn call<T>(f: fn() -> Result<T, AppError>) -> Result<T, AppError> {
        match self.state {
            "open" => {
                // 서킷이 열려있음
                if timestamp() - self.last_failure_time > self.timeout {
                    // 타임아웃 만료 - half-open으로 시도
                    self.state = "half_open"
                    self.success_count = 0
                } else {
                    // 빠르게 실패
                    return Err(AppError::InternalError {
                        component: "CircuitBreaker",
                        message: "Circuit is open",
                        stack_trace: []
                    })
                }
            }
            _ => {}
        }

        match f() {
            Ok(result) => {
                // 성공
                self.failure_count = 0

                if self.state == "half_open" {
                    self.success_count = self.success_count + 1
                    if self.success_count >= self.success_threshold {
                        self.state = "closed"
                    }
                }

                return Ok(result)
            }
            Err(e) => {
                // 실패
                self.failure_count = self.failure_count + 1
                self.last_failure_time = timestamp()

                if self.failure_count >= self.failure_threshold {
                    self.state = "open"
                }

                return Err(e)
            }
        }
    }
}

// 에러 로깅 및 모니터링
@with_observability
fn handle_user_registration(email: string, password: string) -> Result<User, AppError> {
    let logger: Logger = Logger::new("user_registration")
    let metrics: Metrics = Metrics::new()

    logger.info("Starting user registration", {
        "email": email
    })

    // 이메일 검증
    match validate_email(email) {
        Ok() => {
            logger.debug("Email validation passed")
        }
        Err(e) => {
            logger.error("Email validation failed", {
                "email": email,
                "reason": e
            })
            metrics.counter("registration.email_validation_failed").inc()
            return Err(AppError::ValidationError {
                field: "email",
                reason: "Invalid email format"
            })
        }
    }

    // 비밀번호 검증
    match validate_password(password) {
        Ok() => {
            logger.debug("Password validation passed")
        }
        Err(e) => {
            logger.error("Password validation failed", {
                "reason": e
            })
            metrics.counter("registration.password_validation_failed").inc()
            return Err(AppError::ValidationError {
                field: "password",
                reason: "Password too weak"
            })
        }
    }

    // 데이터베이스에 저장
    match save_user_to_db(email, password) {
        Ok(user) => {
            logger.info("User registered successfully", {
                "user_id": user.id,
                "email": user.email
            })
            metrics.counter("registration.success").inc()
            return Ok(user)
        }
        Err(db_error) => {
            logger.error("Database error during registration", {
                "error": db_error
            })
            metrics.counter("registration.database_error").inc()

            // 복구 시도
            let recovery: DatabaseErrorRecovery = DatabaseErrorRecovery::new()
            match recovery.recover(db_error) {
                Ok() => {
                    // 재시도
                    return save_user_to_db(email, password)
                }
                Err(final_error) => {
                    // 최종 실패
                    alert_ops("Critical database error", {
                        "error": final_error
                    })
                    return Err(final_error)
                }
            }
        }
    }
}

