    // "?" 연산자: 에러면 즉시 반환, 성공하면 계속

    match send_verification_email(user.id, email) {
        Ok() => {
            return Ok(user)
        }
        Err(e) => {
            // 이메일 전송 실패 - 사용자는 생성됨
            log_warning("Email verification failed", {
                "user_id": user.id,
                "error": e
            })
            return Ok(user)  // 부분 성공
        }
    }
}

