fn factorial(n: int) -> Result<int, string> {
    if n < 0 {
        return Err("Cannot compute factorial of negative number")
    }
    if n == 0 {
        return Ok(1)
    }
    match factorial(n - 1) {
        Ok(prev_result) => { return Ok(n * prev_result) }
        Err(e) => { return Err(e) }
    }
}
```

