actor Worker {
    id: int,
    busy: bool,
    fn handle_message(msg: WorkerMessage) -> WorkerResponse {
        match msg {
            Task(work_id) => {
                self.busy = true
                let result = self.process_work(work_id)
                self.busy = false
                return Result(result)
            }
            _ => {}
        }
    }
}

async fn concurrent_tasks() -> Result<array<int>, Error> {
    let task1 = spawn(async fn() -> int { return 10 })
    let task2 = spawn(async fn() -> int { return 20 })
    let task3 = spawn(async fn() -> int { return 30 })

    let r1 = task1.await
    let r2 = task2.await
    let r3 = task3.await
    return Ok([r1, r2, r3])
}
```

